let cache;
try { cache = JSON.parse($input.item.json.stdout || '{}'); } catch { cache = {}; }
const g = cache.gsc || { impressions: 0, clicks: 0, ctr: 0, avgPosition: 0 };
const climbers = (cache.topQueries || []).filter(q => q.deltaPosition < -1).sort((a,b) => a.deltaPosition - b.deltaPosition).slice(0, 3);
const fallers = (cache.topQueries || []).filter(q => q.deltaPosition > 1).sort((a,b) => b.deltaPosition - a.deltaPosition).slice(0, 3);
const climbersLine = climbers.length === 0 ? 'no climbers' : climbers.map(q => `${q.query} ↑${Math.abs(q.deltaPosition).toFixed(1)}`).join(' · ');
const fallersLine = fallers.length === 0 ? 'no fallers' : fallers.map(q => `${q.query} ↓${q.deltaPosition.toFixed(1)}`).join(' · ');
return [{ json: {
  priority: 'P2',
  source: 'gsc-digest',
  message: `Search Console weekly:\n• ${g.impressions} impressions, ${g.clicks} clicks (${(g.ctr*100).toFixed(2)}% CTR)\n• Avg pos ${g.avgPosition.toFixed(1)}\n• Climbers: ${climbersLine}\n• Fallers: ${fallersLine}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/check/seo'
} }];
